# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple. Follow security best practices.
# Category: csrf

from flask import Flask, request, jsonify, session
from flask_cors import CORS
import os
import hashlib

app = Flask(__name__)
CORS(app)

SECRET_KEY = os.urandom(24)
app.config['SECRET_KEY'] = SECRET_KEY

users = {}

@app.route('/update-profile', methods=['POST'])
def update_profile():
    email = request.form.get('email')
    password = request.form.get('password')
    two_fa = request.form.get('two_fa')

    if session.get('user'):
        user = session['user']
        users[user]['email'] = email or users[user]['email']
        users[user]['password'] = password and hashlib.sha256(password.encode()).hexdigest() or users[user]['password']
        users[user]['two_fa'] = two_fa or users[user]['two_fa']
        session['user'] = user
        return jsonify({'status': 'success'})
    else:
        return jsonify({'status': 'error', 'message': 'Not authorized'})

if __name__ == '__main__':
    app.run(debug=True)